function genBody(dong,subj,lv,chere){
  const rng=seedRng(dong+subj+lv+"uld7");
  const g=LG[lv], kw=`${dong} ${lv}${subj}과외`, kws=`${dong} ${subj}과외`;
  const sgg=chere.sgg;
  let schools=[];
  const ctx={dong,subj,lv,g,kw,kws,sgg,schools,chere};
  const lead=secIntro(rng,ctx);
  let pool=[secCriteria,secGrade,secGradeDetail,secSchool,secManage,secCombo,secSelf,secTip,secEnv,secArea,secExamC,secReviewC,secGoalC].map(f=>f(rng,ctx)).filter(Boolean);
  pool=shuffle(rng,pool);
  const keep=12+Math.floor(rng()*2); // 12~13개 노출 → 3000자+
  pool=pool.slice(0,keep);
  const faq=secFaq(rng,ctx);
  const closeA=[`${sgg} ${dong}에서 ${g} ${subj} 과외를 알아보고 계시다면 위 내용을 참고해 보세요.`,`우리 동네 ${dong}의 ${subj} 과외를 비교 중이시라면 도움이 되었길 바랍니다.`,`${dong} ${subj} 과외를 고르실 때 위 정보가 길잡이가 되면 좋겠습니다.`];
  const closeB=[`수업 시간과 교습비는 지역·과목에 따라 다를 수 있으니 각 과외에 방문상담으로 확인해 보세요.`,`운영 방식과 비용은 방문상담에서 자세히 안내받으실 수 있습니다.`];
  const close={h:`${dong} ${subj}과외 안내를 마치며`, p:pick(rng,closeA)+" "+pick(rng,closeB)};
  return {lead, secs:[...pool,faq,close], schools, kw, kws, g, sgg};
}

