let _idx=null;
function buildIndex(){
  if(_idx) return _idx;
  const byDong={}, dongInfo={}, bySido={};
  const bySgg={}, sggBySlug={};
  REGIONS.forEach(r=>{
    byDong[r.slug]=r;
    dongInfo[r.slug]={dong:r.dong,sgg:r.sgg,sido:r.sido,slug:r.slug};
    (bySido[r.sido]=bySido[r.sido]||{});
    (bySido[r.sido][r.sgg]=bySido[r.sido][r.sgg]||[]).push(r.slug);
    const gk=`${r.sido}|${r.sgg}`;
    if(!bySgg[gk]){ const slug=sggSlug(r.sido,r.sgg); bySgg[gk]={sido:r.sido,sgg:r.sgg,slug,dongs:[]}; sggBySlug[slug]=gk; }
    bySgg[gk].dongs.push(r.slug);
  });
  _idx={byDong,dongInfo,bySido,bySgg,sggBySlug};
  return _idx;
}
