// ---------- 한글 로마자(슬러그) ----------
function romanizeKo(s){
  const CHO=["g","kk","n","d","tt","r","m","b","pp","s","ss","","j","jj","ch","k","t","p","h"];
  const JUNG=["a","ae","ya","yae","eo","e","yeo","ye","o","wa","wae","oe","yo","u","wo","we","wi","yu","eu","ui","i"];
  const JONG=["","k","k","ks","n","n","n","t","l","lg","lm","lb","ls","lt","lp","lh","m","p","ps","t","t","ng","t","t","k","t","p","h"];
  let out="";
  for(const ch of s){
    const code=ch.charCodeAt(0)-0xAC00;
    if(code<0||code>11171){ if(/[a-z0-9]/i.test(ch)) out+=ch.toLowerCase(); continue; }
    out+=CHO[Math.floor(code/588)]+JUNG[Math.floor((code%588)/28)]+JONG[code%28];
  }
  return out.replace(/[^a-z0-9]/g,"");
}
function sggSlug(sido,sgg){ return `${SIDO_SLUG[sido]||romanizeKo(sido)}-${romanizeKo(sgg)}`; }
function urlSgg(sido,sgg){ return `/gu/${sggSlug(sido,sgg)}`; }
function urlSggSubject(sido,sgg,subj){ return `/gu/${sggSlug(sido,sgg)}/${SUBJ_EN[subj]}`; }
function urlDongSubject(slug,subj){ return `/${slug}/${SUBJ_EN[subj]}`; }
function urlSidoSubject(sido,subj){ return `/region/${SIDO_SLUG[sido]}/${SUBJ_EN[subj]}`; }

