function pageCenter(c){
  const subjList=Object.keys(c.subj||{});
  const subjRows=subjList.map(s=>`<tr><th>${SUBJ_ICON[s]} ${esc(s)}</th><td>${esc((c.subj[s]||[]).map(l=>LG[l]).join(", "))}</td></tr>`).join("");
  const schoolRows=[["초등학교",c.e],["중학교",c.m],["고등학교",c.h]].filter(x=>x[1]&&x[1].length).map(x=>`<tr><th>${x[0]}</th><td>${esc(x[1].join(", "))}</td></tr>`).join("");
  const canonical=SITE_URL+urlCenter(c.id);
  const desc=`${c.sgg} ${c.dong} 과외 정보. 과목별 가능 학년과 인근 학교 안내.`;
  const jsonld=JSON.stringify({"@context":"https://schema.org","@type":"EducationalOrganization","name":c.name,"address":{"@type":"PostalAddress","streetAddress":c.addr,"addressCountry":"KR"},"areaServed":c.dong});
  const summary=`<div class="summary"><div class="row"><span class="item">📍 주소<b>${esc(c.addr)}</b></span></div><div class="row">${c.open?`<span class="item">🕒 운영<b>${esc(c.open)}</b></span>`:""}${c.wk?`<span class="item">📅 주말<b>${esc(c.wk)}</b></span>`:""}</div><div class="badges">${subjList.map(s=>`<span class="badge">${SUBJ_ICON[s]} ${esc(s)}</span>`).join("")}</div></div>`;
  const body=`<h1>${esc(c.dong)} 과외</h1>${summary}
<section class="sec"><h2>지도 가능 과목·학년</h2><table class="schooltbl">${subjRows}</table></section>
${schoolRows?`<section class="sec"><h2>인근 학교</h2><table class="schooltbl">${schoolRows}</table></section>`:""}
<section class="sec"><h2>과외 등록 정보</h2><table class="schooltbl"><tr><th>정식 명칭</th><td>${esc(c.name)}</td></tr><tr><th>등록</th><td>${esc(c.office)}</td></tr></table></section>
<div class="note">상담은 예약제로 운영될 수 있습니다. 정확한 수업 시간 및 교습비는 방문상담을 통해 확인하시기 바랍니다.</div>`;
  const crumb=[{name:"홈",url:"/"},{name:c.sido,url:urlRegion(c.sido)},{name:c.dong,url:urlDong(c.dong)},{name:"과외 안내"}];
  return layout({title:`${c.dong} 과외 | ${c.sgg} 과외 정보`, desc, canonical, jsonld, body, crumb});
}

