// ---------- 페이지: 시도 ----------
function pageRegion(sido){
  const idx=buildIndex(); if(!idx.bySido[sido]) return null;
  const sggs=Object.keys(idx.bySido[sido]).sort();
  const blocks=sggs.map(sgg=>{ const dongs=idx.bySido[sido][sgg].map(s2=>`<a class="chip" href="${urlDong(s2)}">${esc(regionOf(s2).dong)}</a>`); return `<div class="sectitle"><a href="${urlSgg(sido,sgg)}" style="color:var(--accent);text-decoration:none">${esc(sgg)} ›</a></div>${chipsFold(dongs,8)}`; });
  const blocksHtml = blocks.length<=4 ? blocks.join("") : blocks.slice(0,4).join("")+`<details class="morechips"><summary>+ 시군구 ${blocks.length-4}곳 더 보기</summary>${blocks.slice(4).join("")}</details>`;
  const dongCnt=Object.values(idx.bySido[sido]).reduce((s,x)=>s+x.length,0);
  const subjLinks=SUBJECTS.map(s=>`<a class="chip" href="${urlSidoSubject(sido,s)}">${SUBJ_ICON[s]} ${esc(sido)} ${esc(s)}</a>`).join("");
  const summary=`<div class="summary"><div class="row"><span class="item">📍 지역<b>${esc(sido)}</b></span><span class="item">🏙 시군구<b>${sggs.length}곳</b></span><span class="item">🏘 동네<b>${dongCnt}곳</b></span></div></div>`;
  const canonical=SITE_URL+urlRegion(sido);
  const body=`<h1>${esc(sido)} 과외 정보</h1>${summary}<section class="sec"><h2>${esc(sido)} 과목별 과외</h2><div class="chips">${subjLinks}</div></section><section class="sec"><h2>시군구·동네별 과외</h2><p class="subt">시군구명을 누르면 시군구별 과외 페이지로 이동합니다.</p>${blocksHtml}</section>`;
  const crumb=[{name:"홈",url:"/"},{name:"지역별",url:"/regions"},{name:sido}];
  return layout({title:`${sido} 과외 정보 | ${SITE_NAME}`, desc:`${sido} 지역 시군구·동네별 과외 정보. 과목별·학년별 과외를 확인하세요.`, canonical, jsonld:"", body, crumb});
}

// ---------- 페이지: 지역 인덱스 ----------
function pageRegions(){
  const idx=buildIndex();
  const sidos=Object.keys(idx.bySido).sort();
  const grid=sidos.map(sido=>{ const c=Object.values(idx.bySido[sido]).reduce((s,x)=>s+x.length,0); return `<a href="${urlRegion(sido)}">${esc(sido)}<small>${c}개 지역</small></a>`; }).join("");
  return layout({title:`지역별 과외 정보 | ${SITE_NAME}`, desc:"전국 시·도별 과외 정보 목록.", canonical:SITE_URL+"/regions", jsonld:"", body:`<h1>지역별 과외 정보</h1><p class="subt">전국 시·도별 동네 과외 정보입니다.</p><div class="lgrid">${grid}</div>`, crumb:[{name:"홈",url:"/"},{name:"지역별"}]});
}

// ---------- sitemap (인덱스 분할) / robots ----------
const SM_CHUNK=5000;
function allUrls(){
  const idx=buildIndex(); const u=[`${SITE_URL}/`,`${SITE_URL}/regions`];
  Object.keys(idx.bySido).forEach(s=>{ u.push(SITE_URL+urlRegion(s)); SUBJECTS.forEach(sj=>u.push(SITE_URL+urlSidoSubject(s,sj))); });
  Object.values(idx.bySgg).forEach(g=>{ u.push(SITE_URL+urlSgg(g.sido,g.sgg)); SUBJECTS.forEach(sj=>u.push(SITE_URL+urlSggSubject(g.sido,g.sgg,sj))); });
  REGIONS.forEach(r=>{
    u.push(SITE_URL+urlDong(r.slug));
    SUBJECTS.forEach(s=>{ u.push(SITE_URL+urlDongSubject(r.slug,s)); LEVELS.forEach(l=>u.push(SITE_URL+urlPage(r.slug,s,l))); });
  });
  return u;
}
function sitemapIndex(){
  const total=allUrls().length; const n=Math.ceil(total/SM_CHUNK);
  const today=new Date().toISOString().slice(0,10);
  const items=[]; for(let i=1;i<=n;i++) items.push(`<sitemap><loc>${SITE_URL}/sitemap-${i}.xml</loc><lastmod>${today}</lastmod></sitemap>`);
  return new Response(`<?xml version="1.0" encoding="UTF-8"?>\n<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${items.join("\n")}\n</sitemapindex>`,{headers:{"content-type":"application/xml; charset=utf-8"}});
}
function sitemapPart(n){
  const u=allUrls(); const start=(n-1)*SM_CHUNK;
  if(start>=u.length) return notFound();
  const part=u.slice(start,start+SM_CHUNK);
  const body=part.map(x=>`<url><loc>${x}</loc></url>`).join("\n");
  return new Response(`<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${body}\n</urlset>`,{headers:{"content-type":"application/xml; charset=utf-8"}});
}
function rss(){
  const items=[]; 
  REGIONS.slice(0,200).forEach(r=>{ SUBJECTS.forEach(s=>{ const k=`${r.slug}|${s}|중등`; const dt=pageDates(k); items.push({d:r.dong,loc:SITE_URL+urlPage(r.slug,s,"중등"),mod:dt.modified,title:`${r.dong} 중학${s}과외`}); }); });
  items.sort((a,b)=>b.mod-a.mod);
  const top=items.slice(0,50); const now=new Date().toUTCString();
  const itemXml=top.map(it=>`<item><title>${esc(it.title)}</title><link>${it.loc}</link><guid>${it.loc}</guid><pubDate>${new Date(it.mod).toUTCString()}</pubDate><description>${esc(it.d+" 지역 "+it.title+" 정보.")}</description></item>`).join("\n");
  return new Response(`<?xml version="1.0" encoding="UTF-8"?>\n<rss version="2.0"><channel>\n<title>${SITE_NAME}</title>\n<link>${SITE_URL}</link>\n<description>전국 지역별·과목별 과외 정보</description>\n<language>ko</language>\n<lastBuildDate>${now}</lastBuildDate>\n${itemXml}\n</channel></rss>`,{headers:{"content-type":"application/rss+xml; charset=utf-8"}});
}
function llmsTxt(){ const idx=buildIndex(); const lines=["# "+SITE_NAME,"","> "+SITE_NAME+"는 전국 동네별로 초·중·고 1:1 과외와 학습 정보를 지역·과목·학년별로 안내하는 과외 정보 사이트입니다.","","## 핵심 정보","- 지역: 전국 "+Object.keys(idx.bySido).length+"개 시·도, "+Object.keys(idx.bySgg).length+"개 시군구, "+REGIONS.length+"개 읍면동","- 과목: 국어·영어·수학·과학·사회","- 대상: 초등·중학·고교","- 문의: "+PHONE,"","## 주요 페이지"]; lines.push("- 홈: "+SITE_URL+"/"); lines.push("- 지역 목록: "+SITE_URL+"/regions"); Object.keys(idx.bySido).forEach(s=>lines.push("- "+s+" 과외: "+SITE_URL+urlRegion(s))); return new Response(lines.join("\n"),{headers:{"content-type":"text/plain; charset=utf-8"}}); }
