function regLevels(centers, subj){ const s=new Set(); centers.forEach(c=>(c.subj&&c.subj[subj]||[]).forEach(l=>s.add(l))); return LEVELS.filter(l=>s.has(l)); }
function chipsFold(arr, vis){ vis=vis||8; if(arr.length<=vis) return `<div class="chips">${arr.join("")}</div>`;
  return `<div class="chips">${arr.slice(0,vis).join("")}</div><details class="morechips"><summary>+ ${arr.length-vis}개 더 보기</summary><div class="chips">${arr.slice(vis).join("")}</div></details>`; }
function foldGrid(arr, cls, vis){ vis=vis||6; if(arr.length<=vis) return `<div class="${cls}">${arr.join("")}</div>`;
  return `<div class="${cls}">${arr.slice(0,vis).join("")}</div><details class="morechips"><summary>+ ${arr.length-vis}개 더 보기</summary><div class="${cls}" style="margin-top:10px">${arr.slice(vis).join("")}</div></details>`; }
function lvTxtOf(lvs){ const m={"초등":"초등","중등":"중학","고등":"고교"}; return lvs.map(l=>m[l]).join("·"); }

